 4→export default auth((req) => {
 5→  const isLoggedIn = !!req.auth?.user;
 6→  const isOnLogin = req.nextUrl.pathname.startsWith("/login");
 7→
 8→  if (!isLoggedIn && !isOnLogin) {
 9→    return NextResponse.redirect(new URL("/login", req.url));
10→  }
11→
12→  if (isLoggedIn && isOnLogin) {
13→    return NextResponse.redirect(new URL("/", req.url));
14→  }
15→
16→  return NextResponse.next();
17→});
