 1→import NextAuth from "next-auth";
 2→import GitHub from "next-auth/providers/github";
 3→
 4→export const { handlers, auth, signIn, signOut } = NextAuth({
 5→  providers: [
 6→    GitHub({
 7→      clientId: process.env.GITHUB_CLIENT_ID,
 8→      clientSecret: process.env.GITHUB_CLIENT_SECRET,
 9→      authorization: {
10→        params: {
11→          scope: "repo read:user",
12→        },
13→      },
14→    }),
15→  ],
16→  callbacks: {
17→    async jwt({ token, account, profile }) {
18→      if (account) {
19→        token.accessToken = account.access_token;
20→      }
21→      if (profile) {
22→        token.login = (profile as { login?: string }).login;
23→      }
24→      return token;
25→    },
26→    async session({ session, token }) {
27→      session.accessToken = token.accessToken as string | undefined;
28→      if (token.login) {
29→        session.user.login = token.login as string;
30→      }
31→      return session;
32→    },
33→  },
34→  pages: {
35→    signIn: "/login",
36→  },
37→});
