  1→import { Octokit } from "@octokit/rest";
  2→import { listCheckpoints } from "@/lib/github/checkpoints";
  3→import { listCommits } from "@/lib/github/commits";
  4→import type { CheckpointMetadata, OverviewStats } from "@/types/checkpoint";
  5→import type { RepoLatestCheckpoint } from "@/types/repository";
  6→
  7→const RECENT_LIMIT = 10;
  8→
  9→export interface RecentCheckpointsResult {
 10→  items: RepoLatestCheckpoint[];
 11→  heatmap: Record<string, number>;
 12→  stats: OverviewStats;
 13→}
 14→
 15→export async function getRecentCheckpointsForRepos(
 16→  octokit: Octokit,
 17→  repos: { owner: string; name: string }[]
 18→): Promise<RecentCheckpointsResult> {
 19→  const heatmap: Record<string, number> = {};
 20→
 21→  // Pass 1: fetch all checkpoints from every repo, collect heatmap data
 22→  const allCheckpoints: {
 23→    owner: string;
 24→    repo: string;
 25→    checkpoint: CheckpointMetadata;
 26→  }[] = [];
 27→
 28→  await Promise.allSettled(
 29→    repos.map(async (repo) => {
 30→      const checkpoints = await listCheckpoints(
 31→        octokit,
 32→        repo.owner,
 33→        repo.name
 34→      );
 35→
 36→      for (const cp of checkpoints) {
 37→        const date = cp.created_at.split("T")[0];
 38→        heatmap[date] = (heatmap[date] || 0) + 1;
 39→        allCheckpoints.push({ owner: repo.owner, repo: repo.name, checkpoint: cp });
 40→      }
 41→    })
 42→  );
 43→
 44→  // Sort newest-first and take the top N
 45→  allCheckpoints.sort(
 46→    (a, b) =>
 47→      new Date(b.checkpoint.created_at).getTime() -
 48→      new Date(a.checkpoint.created_at).getTime()
 49→  );
 50→  const top = allCheckpoints.slice(0, RECENT_LIMIT);
 51→
 52→  // Pass 2: enrich only the top checkpoints with commit + session data
 53→  const items = await Promise.all(
 54→    top.map(async ({ owner, repo, checkpoint }) => {
 55→      let commit = null;
 56→      try {
 57→        const commits = await listCommits(octokit, owner, repo, {
 58→          sha: checkpoint.commit_hash,
 59→          per_page: 1,
 60→        });
 61→        if (commits.length > 0) commit = commits[0];
 62→      } catch {
 63→        // Commit may no longer exist — that's fine
 64→      }
 65→
 66→      return {
 67→        owner,
 68→        repo,
 69→        checkpoint: {
 70→          id: checkpoint.id,
 71→          commit_hash: checkpoint.commit_hash,
 72→          branch: checkpoint.branch,
 73→          created_at: checkpoint.created_at,
 74→          agent: checkpoint.agent,
 75→          agent_percent: checkpoint.agent_percent,
 76→        },
 77→        commit,
 78→        summary: null,
 79→        session_duration_ms: null,
 80→      } satisfies RepoLatestCheckpoint;
 81→    })
 82→  );
 83→
 84→  // Compute overview stats from the full checkpoint list
 85→  const now = new Date();
 86→  const msPerDay = 86_400_000;
 87→  const weekAgo = now.getTime() - 7 * msPerDay;
 88→  const twoWeeksAgo = now.getTime() - 14 * msPerDay;
 89→
 90→  const uniqueRepos = new Set(
 91→    allCheckpoints.map((c) => `${c.owner}/${c.repo}`)
 92→  );
 93→
 94→  let thisWeek = 0;
 95→  let prevWeek = 0;
 96→  let agentPercentSum = 0;
 97→
 98→  for (const { checkpoint } of allCheckpoints) {
 99→    const t = new Date(checkpoint.created_at).getTime();
100→    if (t >= weekAgo) thisWeek++;
101→    else if (t >= twoWeeksAgo) prevWeek++;
102→    agentPercentSum += checkpoint.agent_percent ?? 0;
103→  }
104→
105→  const avgAgentPercent =
106→    allCheckpoints.length > 0
107→      ? Math.round(agentPercentSum / allCheckpoints.length)
108→      : 0;
109→
110→  // Streak: walk backwards from today through consecutive days with activity
111→  let streakDays = 0;
112→  const todayStr = now.toISOString().split("T")[0];
113→  const d = new Date(todayStr); // start of today (local)
114→  // If today has no activity, check if yesterday does (allow "today hasn't happened yet")
115→  if (!heatmap[todayStr]) {
116→    d.setDate(d.getDate() - 1);
117→  }
118→  while (true) {
119→    const key = d.toISOString().split("T")[0];
120→    if (heatmap[key] && heatmap[key] > 0) {
121→      streakDays++;
122→      d.setDate(d.getDate() - 1);
123→    } else {
124→      break;
125→    }
126→  }
127→
128→  const stats: OverviewStats = {
129→    total_checkpoints: allCheckpoints.length,
130→    active_repos: uniqueRepos.size,
131→    this_week: thisWeek,
132→    prev_week: prevWeek,
133→    avg_agent_percent: avgAgentPercent,
134→    streak_days: streakDays,
135→  };
136→
137→  return { items, heatmap, stats };
138→}
139→

 1→import type { OverviewStats } from "@/types/checkpoint";
