 1→"use client";
 2→
 3→import { cn } from "@/lib/utils";
 4→
 5→interface HeatmapProps {
 6→  data: Record<string, number>;
 7→  className?: string;
 8→}
 9→
10→function getIntensityClass(count: number, max: number): string {
11→  if (count === 0) return "bg-surface-light";
12→  const ratio = count / max;
13→  if (ratio < 0.25) return "bg-accent-dark/30";
14→  if (ratio < 0.5) return "bg-accent-dark/50";
15→  if (ratio < 0.75) return "bg-accent/70";
16→  return "bg-accent";
17→}
18→
19→export function Heatmap({ data, className }: HeatmapProps) {
20→  const today = new Date();
21→  const days = 91; // ~13 weeks
22→  const cells: { date: string; count: number }[] = [];
23→
24→  for (let i = days - 1; i >= 0; i--) {
25→    const d = new Date(today);
26→    d.setDate(d.getDate() - i);
27→    const key = d.toISOString().split("T")[0];
28→    cells.push({ date: key, count: data[key] || 0 });
29→  }
30→
31→  const maxCount = Math.max(...cells.map((c) => c.count), 1);
32→
33→  // Group by week (columns)
34→  const weeks: { date: string; count: number }[][] = [];
35→  let currentWeek: { date: string; count: number }[] = [];
36→
37→  for (const cell of cells) {
38→    const dayOfWeek = new Date(cell.date).getDay();
39→    if (dayOfWeek === 0 && currentWeek.length > 0) {
40→      weeks.push(currentWeek);
41→      currentWeek = [];
42→    }
43→    currentWeek.push(cell);
44→  }
45→  if (currentWeek.length > 0) {
46→    weeks.push(currentWeek);
47→  }
48→
49→  return (
50→    <div className={cn("rounded-xl border border-border bg-surface p-5", className)}>
51→      <p className="mb-3 text-xs font-medium uppercase tracking-wider text-muted">
52→        Activity
53→      </p>
54→      <div className="flex gap-1">
55→        {weeks.map((week, wi) => (
56→          <div key={wi} className="flex flex-col gap-1">
57→            {week.map((cell) => (
58→              <div
59→                key={cell.date}
60→                className={cn(
61→                  "h-3 w-3 rounded-sm transition-colors",
62→                  getIntensityClass(cell.count, maxCount)
63→                )}
64→                title={`${cell.date}: ${cell.count} checkpoint${cell.count !== 1 ? "s" : ""}`}
65→              />
66→            ))}
67→          </div>
68→        ))}
69→      </div>
70→      <div className="mt-3 flex items-center gap-1.5 text-xs text-muted">
71→        <span>Less</span>
72→        <div className="h-3 w-3 rounded-sm bg-surface-light" />
73→        <div className="h-3 w-3 rounded-sm bg-accent-dark/30" />
74→        <div className="h-3 w-3 rounded-sm bg-accent-dark/50" />
75→        <div className="h-3 w-3 rounded-sm bg-accent/70" />
