 12→function PlanTitle({ owner, repo, checkpointId }: { owner: string; repo: string; checkpointId: string }) {
 13→  const { plan } = usePlan(owner, repo, checkpointId);
 14→  if (!plan) return null;
 15→  const heading = plan.split("\n").find((l) => /^#+\s/.test(l));
 16→  const title = heading?.replace(/^#+\s*/, "").trim();
 17→  if (!title) return null;
 18→  return (
 19→    <>
 20→      <span className="truncate text-foreground/60">{title}</span>
 21→      <span>&middot;</span>
 22→    </>
 23→  );
