 26→export default function CheckpointsPage({
 27→  params,
 28→}: {
 29→  params: Promise<{ owner: string; repo: string }>;
 30→}) {
 31→  const { owner, repo } = use(params);
 32→  const { checkpoints, isLoading } = useCheckpoints(owner, repo);
 33→  const { commits } = useCommits(owner, repo);
 34→
 35→  // Map commit SHA prefix → commit message
 36→  const commitMessages = useMemo(() => {
 37→    const map = new Map<string, string>();
 38→    if (commits) {
 39→      for (const c of commits) {
 40→        map.set(c.sha, c.message.split("\n")[0]);
 41→      }
 42→    }
 43→    return map;
 44→  }, [commits]);
 45→
 46→  function findCommitMessage(commitHash: string): string | undefined {
 47→    // Try exact match first, then prefix match
 48→    const exact = commitMessages.get(commitHash);
 49→    if (exact) return exact;
 50→    for (const [sha, msg] of commitMessages) {
 51→      if (sha.startsWith(commitHash) || commitHash.startsWith(sha)) {
 52→        return msg;
 53→      }
 54→    }
 55→    return undefined;
 56→  }
 57→
 58→  if (isLoading) {
 59→    return (
 60→      <div className="space-y-2">
 61→        <Skeleton className="h-16" />
 62→        <Skeleton className="h-16" />
 63→        <Skeleton className="h-16" />
 64→      </div>
 65→    );
 66→  }
 67→
 68→  if (!checkpoints || checkpoints.length === 0) {
 69→    return (
 70→      <EmptyState
 71→        title="No checkpoints found"
 72→        description="This repository doesn't have any checkpoints on the partio/checkpoints/v1 branch yet."
 73→      />
 74→    );
 75→  }
 76→
 77→  return (
 78→    <div className="space-y-2">
 79→      {checkpoints.map((cp) => {
 80→        const message = findCommitMessage(cp.commit_hash);
 81→        return (
 82→          <Link
 83→            key={cp.id}
 84→            href={`/${owner}/${repo}/checkpoints/${cp.id}`}
 85→            className="block rounded-xl border border-border bg-surface p-4 transition-colors hover:border-accent/30 hover:bg-surface-light"
 86→          >
 87→            <div className="flex items-center gap-3">
 88→              <span className="font-mono text-sm text-foreground">
 89→                {cp.id}
 90→              </span>
 91→              <Badge>{cp.branch}</Badge>
 92→              <span className="flex-1" />
 93→              <span className="whitespace-nowrap text-xs text-muted">
 94→                {formatDistanceToNow(new Date(cp.created_at), {
 95→                  addSuffix: true,
 96→                })}
 97→              </span>
 98→            </div>
 99→            <div className="mt-1.5 flex items-center gap-2 text-xs text-muted">
100→              <span className="font-mono">
101→                {cp.commit_hash.slice(0, 8)}
102→              </span>
103→              <span>&middot;</span>
104→              {message ? (
105→                <span className="truncate">{message}</span>
106→              ) : commits ? (
