 5→export async function getCheckpointDiff(
 6→  octokit: Octokit,
 7→  owner: string,
 8→  repo: string,
 9→  checkpointId: string
10→): Promise<string> {
11→  const shard = checkpointId.slice(0, 2);
12→  const rest = checkpointId.slice(2);
13→
14→  try {
15→    const { data: ref } = await octokit.git.getRef({
16→      owner,
17→      repo,
18→      ref: `heads/${CHECKPOINT_BRANCH}`,
19→    });
20→
21→    const { data: commit } = await octokit.git.getCommit({
22→      owner,
23→      repo,
24→      commit_sha: ref.object.sha,
25→    });
26→
27→    const { data: tree } = await octokit.git.getTree({
28→      owner,
29→      repo,
30→      tree_sha: commit.tree.sha,
31→      recursive: "1",
32→    });
33→
34→    const diffPath = `${shard}/${rest}/0/diff.patch`;
35→    const entry = (tree.tree || []).find((e) => e.path === diffPath);
36→
37→    if (!entry?.sha) return "";
38→
39→    const { data: blob } = await octokit.git.getBlob({
40→      owner,
41→      repo,
42→      file_sha: entry.sha,
43→    });
44→
45→    return Buffer.from(blob.content, "base64").toString("utf-8");
46→  } catch {
47→    return "";
48→  }
49→}
