 29→function extractToolNames(content: string): string[] {
 30→  const matches = content.match(/\[Tool: (.+?)\]/g);
 31→  if (!matches) return [];
 32→  return matches.map((m) => m.replace("[Tool: ", "").replace("]", ""));
 33→}
