 35→function stripToolPatterns(content: string): string {
 36→  return content
 37→    .replace(/\[Tool: .+?\]/g, "")
 38→    .replace(/\[Tool Result: [\s\S]*?\]/g, "")
 39→    .replace(/\n{3,}/g, "\n\n")
 40→    .trim();
 41→}
