 43→function formatDuration(ms: number): string {
 44→  const seconds = Math.floor(ms / 1000);
 45→  if (seconds < 60) return `${seconds}s`;
 46→  const minutes = Math.floor(seconds / 60);
 47→  const remainingSeconds = seconds % 60;
 48→  if (minutes < 60) return `${minutes}m ${remainingSeconds}s`;
 49→  const hours = Math.floor(minutes / 60);
 50→  const remainingMinutes = minutes % 60;
 51→  return `${hours}h ${remainingMinutes}m`;
 52→}
 53→
 54→function computeSessionStats(messages: Message[]): SessionStats {
 55→  const humanMessages = messages.filter(
 56→    (m) => m.role === "human" || m.role === "user"
 57→  );
 58→  const prompt =
 59→    humanMessages.length > 0
 60→      ? humanMessages[0].content.slice(0, 80) +
 61→        (humanMessages[0].content.length > 80 ? "..." : "")
 62→      : "Session";
 63→
 64→  const allToolNames: string[] = [];
 65→  for (const msg of messages) {
 66→    allToolNames.push(...extractToolNames(msg.content));
 67→  }
 68→  const uniqueTools = [...new Set(allToolNames)];
 69→
 70→  const totalTokens = messages.reduce((sum, m) => sum + (m.tokens || 0), 0);
 71→
 72→  let duration = "—";
 73→  if (messages.length >= 2) {
 74→    const first = new Date(messages[0].timestamp).getTime();
 75→    const last = new Date(messages[messages.length - 1].timestamp).getTime();
 76→    if (!isNaN(first) && !isNaN(last) && last > first) {
 77→      duration = formatDuration(last - first);
 78→    }
 79→  }
 80→
 81→  let startTime = "";
 82→  if (messages.length > 0) {
 83→    const d = new Date(messages[0].timestamp);
 84→    if (!isNaN(d.getTime())) {
 85→      startTime = d.toLocaleTimeString([], {
 86→        hour: "2-digit",
 87→        minute: "2-digit",
 88→      });
 89→    }
