206→function groupMessages(messages: Message[]): Message[] {
207→  const result: Message[] = [];
208→  for (const msg of messages) {
209→    const isAssistant = msg.role === "assistant";
210→    const textContent = isAssistant ? stripToolPatterns(msg.content).trim() : "";
211→    const toolNames = isAssistant ? extractToolNames(msg.content) : [];
212→    const isToolOnly = isAssistant && textContent === "" && toolNames.length > 0;
213→
214→    const prev = result[result.length - 1];
215→    if (
216→      isToolOnly &&
217→      prev &&
218→      prev.role === "assistant" &&
219→      stripToolPatterns(prev.content).trim() === "" &&
220→      extractToolNames(prev.content).length > 0
221→    ) {
222→      // Merge: append tool markers to previous message's content
223→      prev.content += "\n" + msg.content;
224→      // Keep the later timestamp and sum tokens
225→      prev.tokens = (prev.tokens || 0) + (msg.tokens || 0);
226→    } else {
227→      result.push({ ...msg });
228→    }
229→  }
230→  return result;
231→}
